# 生成 TabBar 图标
# 运行方式: 右键 -> 使用 PowerShell 运行

$iconsDir = Join-Path $PSScriptRoot "assets\icons"

# 确保目录存在
if (-not (Test-Path $iconsDir)) {
    New-Item -ItemType Directory -Path $iconsDir -Force | Out-Null
}

# Base64 图标数据
$icons = @{
    "home.png" = ""
    "home-active.png" = ""
    "clubs.png" = ""
    "clubs-active.png" = ""
    "grades.png" = ""
    "grades-active.png" = ""
    "messages.png" = ""
    "messages-active.png" = ""
    "profile.png" = ""
    "profile-active.png" = ""
}

# 生成图标文件
foreach ($name in $icons.Keys) {
    $filepath = Join-Path $iconsDir $name
    $bytes = [Convert]::FromBase64String($icons[$name])
    [System.IO.File]::WriteAllBytes($filepath, $bytes)
    Write-Host "Created: $name" -ForegroundColor Green
}

Write-Host "`n✅ All icons generated successfully!" -ForegroundColor Cyan
Write-Host "Refresh your WeChat DevTools to see the icons."
